import numpy as np

class QuantumAdvantageTimeline:
    """
    Project timeline for quantum advantage.
    """

    def __init__(self, start_year=2024):
        self.start_year = start_year

        self.current_qubits = 1000
        self.current_error = 1e-3
        self.current_ops_per_sec = 1e4

        self.qubit_growth = 2.0
        self.error_improvement = 0.7
        self.speed_improvement = 1.5

    def project_hardware(self, year):
        """Project hardware capabilities for a given year."""
        years_elapsed = year - self.start_year

        qubits = self.current_qubits * (self.qubit_growth ** years_elapsed)
        error = self.current_error * (self.error_improvement ** years_elapsed)
        speed = self.current_ops_per_sec * (self.speed_improvement ** years_elapsed)

        return {
            'year': year,
            'qubits': int(qubits),
            'error': error,
            'ops_per_sec': speed
        }

    def requirements_for_problem(self, problem_type):
        """Get hardware requirements for different problems."""
        requirements = {
            'simple_option': {
                'qubits': 100000,
                'error': 1e-6,
                'ops_per_sec': 1e6
            },
            'barrier_option': {
                'qubits': 200000,
                'error': 1e-7,
                'ops_per_sec': 1e6
            },
            'portfolio': {
                'qubits': 500000,
                'error': 1e-8,
                'ops_per_sec': 1e7
            },
            'risk_management': {
                'qubits': 1000000,
                'error': 1e-9,
                'ops_per_sec': 1e8
            }
        }
        return requirements.get(problem_type, requirements['simple_option'])

    def year_for_advantage(self, problem_type):
        """Calculate when quantum advantage is achieved for a problem."""
        req = self.requirements_for_problem(problem_type)

        for year in range(self.start_year, 2060):
            hw = self.project_hardware(year)

            qubits_ok = hw['qubits'] >= req['qubits']
            error_ok = hw['error'] <= req['error']
            speed_ok = hw['ops_per_sec'] >= req['ops_per_sec']

            if qubits_ok and error_ok and speed_ok:
                return year

        return 2060

    def generate_roadmap(self):
        """Generate roadmap for quantum advantage milestones."""
        problems = ['simple_option', 'barrier_option', 'portfolio', 'risk_management']

        roadmap = {}
        for problem in problems:
            year = self.year_for_advantage(problem)
            if year not in roadmap:
                roadmap[year] = []
            roadmap[year].append(problem)

        return roadmap

if __name__ == "__main__":
    timeline = QuantumAdvantageTimeline()

    print("Hardware Projections:")
    for year in [2025, 2028, 2030, 2035, 2040]:
        hw = timeline.project_hardware(year)
        print(f"  {year}: {hw['qubits']:,} qubits, {hw['error']:.0e} error")

    print("\nQuantum Advantage Timeline:")
    for problem in ['simple_option', 'portfolio', 'risk_management']:
        year = timeline.year_for_advantage(problem)
        print(f"  {problem}: {year}")

    print("\nRoadmap:")
    roadmap = timeline.generate_roadmap()
    for year in sorted(roadmap.keys()):
        print(f"  {year}: {', '.join(roadmap[year])}")
